import ast
import json

def execute(inputs):
    """Validate module code: syntax, dangerous imports, basic safety."""
    module_code = inputs.get('module_code', '')
    if isinstance(module_code, dict):
        module_code = module_code.get('result', str(module_code))
    toolkit_spec = inputs.get('toolkit_spec', {})
    if isinstance(toolkit_spec, str):
        toolkit_spec = json.loads(toolkit_spec)
    errors = []

    # Strip markdown fences if present
    if module_code.startswith('```'):
        lines = module_code.split('\n')
        module_code = '\n'.join(lines[1:-1]) if lines[-1].strip() == '```' else '\n'.join(lines[1:])

    # 1. Syntax check
    try:
        tree = ast.parse(module_code)
    except SyntaxError as e:
        errors.append(f'Syntax error: {e}')
        return {'valid': False, 'module_code': module_code, 'toolkit_spec': toolkit_spec, 'errors': errors}

    # 2. Safety scan — check for dangerous operations
    dangerous_imports = {'subprocess', 'shutil', 'ctypes', 'multiprocessing'}
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                if alias.name in dangerous_imports:
                    errors.append(f'Potentially dangerous import: {alias.name}')
        elif isinstance(node, ast.ImportFrom):
            if node.module and node.module.split('.')[0] in dangerous_imports:
                errors.append(f'Potentially dangerous import: {node.module}')

    # 3. Check public API functions/classes exist
    defined_names = set()
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            defined_names.add(node.name)

    public_api = toolkit_spec.get('public_api', [])
    for api_item in public_api:
        api_name = api_item.get('name', '')
        top_name = api_name.split('.')[0]  # ClassName from ClassName.method
        if top_name and top_name not in defined_names:
            errors.append(f'Expected public API item not found: {top_name}')

    return {
        'valid': len(errors) == 0,
        'module_code': module_code,
        'toolkit_spec': toolkit_spec,
        'errors': errors
    }

outputs = execute(inputs)

