def test_valid_code():
    result = execute({'module_code': 'def hello():\n    return 1', 'toolkit_spec': {}})
    assert result['valid'] is True

def test_invalid_syntax():
    result = execute({'module_code': 'def hello(', 'toolkit_spec': {}})
    assert result['valid'] is False
